import time

from thrift.transport import TSocket
from thrift.transport import TTransport
from thrift.protocol import TBinaryProtocol


class BaseClient:
  def __init__(self, thrift_service_client_cls, ip_address, port, timeout,
      logger, connection_pool):
    self._ip_address = ip_address
    self._port = port
    self._socket = TSocket.TSocket(ip_address, port)
    self._socket.setTimeout(timeout)
    self._transport = TTransport.TBufferedTransport(self._socket)
    self._protocol = TBinaryProtocol.TBinaryProtocol(self._transport)
    self._tclient = thrift_service_client_cls(self._protocol)
    self._transport.open()
    self._logger = logger
    self._connection_pool = connection_pool

  def __enter__(self):
    return self

  def __exit__(self, exception_type, exception_value, exception_traceback):
    if self._connection_pool:
      self._connection_pool.release_client(self)
    else:
      self.close()

  def __del__(self):
    self.close()

  def close(self):
    self._transport.close()

  def rpc_wrapper(self, request_id, function_name):
    def wrapper(f, *args, **kwargs):
      start_time = time.monotonic()
      ret = f(*args, **kwargs)
      latency = time.monotonic() - start_time
      if self._logger:
        self._logger.info(
            "request_id=%s server=%s:%s function=%s latency=%.9f" %
            (request_id, self._ip_address, self._port, function_name, latency))
      return ret
    return wrapper
